import{_ as s,o as e,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const k=JSON.parse('{"title":"Gateway on macOS","description":"","frontmatter":{"summary":"Gateway runtime on macOS (external launchd service)","read_when":["Packaging OpenSoul.app","Debugging the macOS gateway launchd service","Installing the gateway CLI for macOS"],"title":"Gateway on macOS"},"headers":[],"relativePath":"platforms/mac/bundled-gateway.md","filePath":"platforms/mac/bundled-gateway.md","lastUpdated":null}'),t={name:"platforms/mac/bundled-gateway.md"};function l(p,a,h,o,r,d){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="gateway-on-macos-external-launchd" tabindex="-1"><a class="header-anchor" href="#gateway-on-macos-external-launchd">#</a> Gateway on macOS (external launchd)</h1><p>OpenSoul.app no longer bundles Node/Bun or the Gateway runtime. The macOS app expects an <strong>external</strong> <code>opensoul</code> CLI install, does not spawn the Gateway as a child process, and manages a per‑user launchd service to keep the Gateway running (or attaches to an existing local Gateway if one is already running).</p><h2 id="install-the-cli-required-for-local-mode" tabindex="-1"><a class="header-anchor" href="#install-the-cli-required-for-local-mode">#</a> Install the CLI (required for local mode)</h2><p>You need Node 22+ on the Mac, then install <code>opensoul</code> globally:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The macOS app’s <strong>Install CLI</strong> button runs the same flow via npm/pnpm (bun not recommended for Gateway runtime).</p><h2 id="launchd-gateway-as-launchagent" tabindex="-1"><a class="header-anchor" href="#launchd-gateway-as-launchagent">#</a> Launchd (Gateway as LaunchAgent)</h2><p>Label:</p><ul><li><code>ai.opensoul.gateway</code> (or <code>ai.opensoul.&lt;profile&gt;</code>; legacy <code>com.opensoul.*</code> may remain)</li></ul><p>Plist location (per‑user):</p><ul><li><code>~/Library/LaunchAgents/ai.opensoul.gateway.plist</code> (or <code>~/Library/LaunchAgents/ai.opensoul.&lt;profile&gt;.plist</code>)</li></ul><p>Manager:</p><ul><li>The macOS app owns LaunchAgent install/update in Local mode.</li><li>The CLI can also install it: <code>opensoul gateway install</code>.</li></ul><p>Behavior:</p><ul><li>“OpenSoul Active” enables/disables the LaunchAgent.</li><li>App quit does <strong>not</strong> stop the gateway (launchd keeps it alive).</li><li>If a Gateway is already running on the configured port, the app attaches to it instead of starting a new one.</li></ul><p>Logging:</p><ul><li>launchd stdout/err: <code>/tmp/opensoul/opensoul-gateway.log</code></li></ul><h2 id="version-compatibility" tabindex="-1"><a class="header-anchor" href="#version-compatibility">#</a> Version compatibility</h2><p>The macOS app checks the gateway version against its own version. If they’re incompatible, update the global CLI to match the app version.</p><h2 id="smoke-check" tabindex="-1"><a class="header-anchor" href="#smoke-check">#</a> Smoke check</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_SKIP_CHANNELS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_SKIP_CANVAS_HOST=1 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">opensoul </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18999</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> loopback</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Then:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ws://127.0.0.1:18999</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --timeout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,23)])])}const u=s(t,[["render",l]]);export{k as __pageData,u as default};
